void MRFSegmentVentDlg::ClearAllSelections()
{
	if (!!_pSurfaceSelector)
		_pSurfaceSelector->ClearSelect();

	if (!!_pVentSelector)
		_pVentSelector->ClearSelect();
}


//-----------------------------------------------------------------------------
// MRFSegmentVentDlg : SetFocusOnSelectorList
// Set focus on the selected List
//-----------------------------------------------------------------------------
void MRFSegmentVentDlg::SetFocusOnSelectorList(CATDlgSelectorList * ipSelectorList)
{
	if (!!ipSelectorList)
	{
		static int arrRow[1] = { 0 };
		ipSelectorList->SetSelect(arrRow, 1, 0);
		SetFocusOn(ipSelectorList);

	}
}

void MRFSegmentVentDlg::UpdateUVValues(double iU, double iV)
{
	float U = (float)iU;
	float V = (float)iV;
	_pRefVentU->SetFloatValue(U);
	_pRefVentV->SetFloatValue(V);
}

void MRFSegmentVentDlg::UpdateDeltaUVValues(double iDeltaU, double iDeltaV)
{
	float U = (float)iDeltaU;
	float V = (float)iDeltaV;
	_pRefVentDeltaU->SetCurrentValue(U);
	_pRefVentDeltaV->SetCurrentValue(V);
}

void MRFSegmentVentDlg::GetUVValues(double & oU, double & oV)
{
	float U = 0.f;
	float V = 0.f;
	U = _pRefVentU->GetFloatValue();
	V = _pRefVentV->GetFloatValue();

	oU = (double)U;
	oV = (double)V;
}

void MRFSegmentVentDlg::GetDeltaUVValues(double & oDeltaU, double & oDeltaV)
{
	float U = 0.f;
	float V = 0.f;
	U = _pRefVentDeltaU->GetCurrentValue();
	V = _pRefVentDeltaV->GetCurrentValue();

	oDeltaU = (double)U;
	oDeltaV = (double)V;
}

void MRFSegmentVentDlg::ModifyFrameForPitchVent(int iVentType)
{
	this->SetTitle("Modify MRF Point Vent");

	CATUnicodeString strType = "";

	if (0 == iVentType)
		strType = CATMsgCatalog::BuildMessage("MRFPointVentHeader", "MRFPointVentDlg.MRFVentModelType.SingleEdge");
	else if (1 == iVentType)
		strType = CATMsgCatalog::BuildMessage("MRFPointVentHeader", "MRFPointVentDlg.MRFVentModelType.DualEdge");
	else if (2 == iVentType)
		strType = CATMsgCatalog::BuildMessage("MRFPointVentHeader", "MRFPointVentDlg.MRFVentModelType.ReferenceCurveAndEdge");
	else if (3 == iVentType)
		strType = CATMsgCatalog::BuildMessage("MRFPointVentHeader", "MRFPointVentDlg.MRFVentModelType.ReferenceEdgeAndVent");
	else if (4 == iVentType)
		strType = CATMsgCatalog::BuildMessage("MRFPointVentHeader", "MRFPointVentDlg.MRFVentModelType.TwoVent");
	else if (6 == iVentType)
		strType = CATMsgCatalog::BuildMessage("MRFPointVentHeader", "MRFPointVentDlg.MRFVentModelType.CentroidVent");

	_pVentModelType->ClearLine();
	_pVentModelType->SetLine(strType);

	_pSegmentFrame->SetTitle("Move Vent For Pitch Vent Analysis");
	_pUVFrame->SetTitle("U & V values of Reference Vent on Reference Surface");

}